var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"눈보라가 심해서 더이상 계기 비행으로도 접근이 어렵네요. 착륙하겠습니다.","JPN":"吹雪が酷くてこれ以上は計器飛行でも近づけないです。着陸します。","ENG":"The blizzard is getting more severe, and we can't get any closer by flight. Proceeding to land.","TWN":"暴風雪太大，我們無法繼續透過儀錶飛行靠近，只能著陸了。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 해주게.","JPN":"そうしたまえ。","ENG":"Understood.","TWN":"好吧。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_BUILD_SKILL_LOOP"},{"id":"L8_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"이런!","JPN":"そんな！","ENG":"Damn!","TWN":"糟糕！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"전방에 미확인 기체! 충돌합니다!","JPN":"前方に未確認機体！　衝突します！","ENG":"Unidentified aircraft in front! Brace for impact!","TWN":"前方有不明機體！要撞上了！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으음…? 네엥? 머라구여??","JPN":"ううん……？　ふぁい？　なんですかぁ？？","ENG":"Mm...? Huh? What did you say??","TWN":"嗯……？什麼什麼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐갸아앗…?!","JPN":"ふぎゃああ……！？","ENG":"Eeeep...?!","TWN":"呀啊啊……？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"무슨 일이죠?!","JPN":"どうしたんですか！？","ENG":"What's going on?!","TWN":"什麼事？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"창 밖을 봐. 눈보라 사이에 시커먼 것들이 날아다니고 있어.","JPN":"窓の外を見ろ。吹雪の中を真っ黒いやつらが飛んでいる。","ENG":"Look out the window. There are pitch-black things flying within the blizzard.","TWN":"看窗外，有一些漆黑的東西在風雪中飛過。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저건 비행형 침식체잖아요?","JPN":"あれは飛行型の侵食体じゃないですか！","ENG":"Aren't those flying C.O.s?","TWN":"那是飛行侵蝕體？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"히익, 엄청 많네요. 어느새 이렇게 둘러싸인 거지?","JPN":"ひいっ、多すぎますね。いつの間に囲まれたの？","ENG":"Eek...! There are so many of them. When did they surround us?","TWN":"啊，太多了。什麼時候冒出了這麼多？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"돌진해온다! 뭐라도 붙잡아!","JPN":"突進してくる！　何かに掴まれ！","ENG":"They're charging toward us! Grab onto something!","TWN":"來了！快抓穩！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"뭐지? 계기판 고장인가?","JPN":"何だ？　計器板が故障したのか？","ENG":"Huh? Is the dashboard broken?","TWN":"怎麼回事？儀錶板故障？"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"분명 부딪혔는데, 기체에 손상이 없다고?","JPN":"確かにぶつかったのに、機体に損傷がない？","ENG":"Something hit us, but the aircraft took no damage?","TWN":"明明被擊中了，飛機卻沒有損壞？"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이건… 보호막이잖아? 당신이 한 거야?","JPN":"これは……バリアじゃない？　あなたがやったの？","ENG":"This is... a barrier? Did you do this?","TWN":"這是……這是盾防護網？ 是你弄的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"급한 대로 막고 있긴 하지만…","JPN":"取りあえず防いではいますが……","ENG":"I did what I could, given the circumstances. But...","TWN":"我正在盡力阻止了，但是……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저도 이 힘을 컨트롤해 본 적이 별로 없어서 얼마나 버텨 줄진 몰라요.","JPN":"この力をコントロールしたことがあまりないので、いつまでもつかはわかりません。","ENG":"I'm not used to controlling this power, so I don't know how long I can hold it.","TWN":"我對這個力量還不太熟悉，不知道還能撐多久。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리가 레아 양과 처음 만났을 때도 이 능력을 사용했었지.","JPN":"私たちがレア君と始めて会った時も、この力を使っていたな。","ENG":"Leah used this ability when we first met her too.","TWN":"在我們第一次見到蕾亞時也使用過這種能力。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"다행이네요.","JPN":"助かりました。","ENG":"That's good news.","TWN":"太好了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨가 오늘 카운터가 되지 않았으면 저흰 꼼짝없이 추락했을 거예요.","JPN":"レアさんが今日カウンターになっていなかったら私たちは間違いなく墜落していました。","ENG":"If Leah hadn't become a Counter today, the aircraft would've crashed with us inside it.","TWN":"要不是今天蕾亞變成了制裁者，我們早就墜落到地面了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저 사람이 오늘 카운터가 됐다고…?","JPN":"あの人がカウンターになったって？","ENG":"She became a Counter today...?","TWN":"她在今天成為了制裁者……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 네! 레아 씨는 어제까지만 해도 능력이 없는 평범한 사람이었거든요.","JPN":"はい！　レアさんは昨日までは能力を持たないただの人間でしたから。","ENG":"Oh, yes! Leah was an ordinary person with no powers until today.","TWN":"啊，是的！蕾亞在昨天還只是一個沒任何能力的普通人。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"위기를 극복하기 위해 카운터로 각성하기도 한다는 게 사실이었네요.","JPN":"危機を克服するためにカウンターとして覚醒することもあるという話は本当だったんですね。","ENG":"So I guess it's true that people awaken as Counters to overcome danger.","TWN":"人會為了克服危機覺醒為制裁者的傳聞竟然是真的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저도 카운터긴 하지만, 제 능력은 침식체들에게 둘러싸였을 때 딱히 쓸모가 없거든요.","JPN":"私もカウンターですけど、私の能力は侵食体に囲まれた時は余り役に立たないんです。","ENG":"I'm also a Counter, but my abilities are useless when surrounded by C.O.s.","TWN":"我雖然也是制裁者，但我的能力在被侵蝕體包圍的情況下發揮不出任何作用。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나도 처음엔 자네처럼 레아 양이 카운터라고 생각했네.","JPN":"私も最初は君と同じくレア君がカウンターだと思ったな。","ENG":"I also thought that Leah was a Counter at first.","TWN":"和你一樣，我最初也以為蕾亞是制裁者。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그녀는 카운터가 아닐세, 크리스 양.","JPN":"だが、彼女はカウンターではないぞ、クリス君。","ENG":"But she's not, Chris.","TWN":"但她並不是制裁者，克莉絲。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네? 그게 무슨 말씀이세요?","JPN":"はい？　それはどういうことですか？","ENG":"What? I don't understand.","TWN":"嗯？什麼意思？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨는 카운터예요. 방금도 레아 씨 능력 덕분에 저희가 무사한 거잖아요.","JPN":"レアさんはカウンターですよ。今もレアさんの能力のおかげで私たちは無事だったんじゃないですか。","ENG":"Leah is a Counter. We're still alive because she used her powers just now.","TWN":"蕾亞是制裁者沒錯呀，剛才不也使用她的能力救了我們嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 카운터가 가지고 있어야 할 워치는 어디에 있지?","JPN":"なら、カウンターが持っているべきウォッチはどこにある？","ENG":"Then, where is her Watch that every Counter should have?","TWN":"如果是這樣，制裁者的能量環在哪裡？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네? 그건… 저도 아직 잘 모르겠는데요.","JPN":"はい？　それは……私にもまだよくわかりません。","ENG":"Huh? That... I'm not so sure.","TWN":"嗯？這……我也不清楚。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨, 카운터 워치도 손에 넣으신 거죠?","JPN":"レアさん、カウンターウォッチもありますよね？","ENG":"Leah, you obtained a Counter Watch, right?","TWN":"蕾亞，你已經拿到制裁者能量環了對不對？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"중사. 나에게 워치 같은 건 없어.","JPN":"軍曹。私にウォッチはない。","ENG":"Sergeant. I don't have a Watch.","TWN":"中士，我沒有什麼能量環。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"에이, 그럴 리가요. 카운터라면 분명 있을 거라고요.","JPN":"そんなはずないです。 カウンターなら必ずあるはずですよ。","ENG":"Come on, stop kidding. I'm sure you have one if you're a Counter.","TWN":"不，這不可能。制裁者都會擁有一個能量環。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"중사, 난 그림자이기 전에 카운터였어. 내 워치나 다름없던 성흔은 오래 전에 사라졌고.","JPN":"軍曹、私はシャドウである以前はカウンターだった。私にとってウォッチと同じだった聖痕は大昔に無くなったんだ。","ENG":"Sergeant, I was a Counter before I became a Shadow. But my Stigmata, which was basically my Watch, is long gone.","TWN":"中士，在我成為暗影之前是一個制裁者，作為我的能量環的聖痕早就消失了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"오늘 이 힘을 처음으로 썼을 때 느낀 감각은, 카운터가 됐을 때와는 달랐어.","JPN":"今日この力を初めて使った時の感覚は、カウンターになったときとは違った。","ENG":"What I felt when I first used this ability was different from when I first became a Counter.","TWN":"今天在我第一次使用這股力量的感覺與成為制裁者的時候並不一樣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"오히려 그림자가 됐을 때와 비슷한… 불쾌한 감각이었지.","JPN":"むしろシャドウになったときに似た……不快な感覚だったな。","ENG":"It felt similar to that of when I became a Shadow... An unpleasant feeling.","TWN":"反而更像成為暗影時的那種……令人不快的感覺。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"불쾌한… 감각이라고요?","JPN":"不快な……感覚ですか？","ENG":"Unpleasant... feeling?","TWN":"令人不快的……感覺？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 존재는 자신의 세계와 운명이 이어져 있다네.","JPN":"すべての存在は自分の世界と運命に繋がっている。","ENG":"The fate of all beings is tied to that of their worlds.","TWN":"所有存在的命運都與自己的世界緊緊相連。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"레아 양이 불현듯 힘을 얻게 된 건 간절한 바람이나 우연 때문이 아니야.","JPN":"レア君が思いがけず力を手に入れたのは、切実な願いや偶然のためではない。","ENG":"Leah did not suddenly gain her powers through a coincidence or desperate wishes.","TWN":"蕾亞突然獲得力量並不是因為誠懇的盼望或偶然。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"스완이 그녀의 세계, 엘리시온으로 통하는 문을 열었기 때문일세.","JPN":"スワンが彼女の世界、エリシオンへの扉を開いたからなのだ。","ENG":"I believe it's because Swan opened a portal that connects to Elysion, Leah's original world.","TWN":"而是因為史旺已經打開了通往她的世界——艾利森的大門。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네? 잘 모르겠는데요. 그럼 레아 씨는 대체 무슨 힘을 사용하고 있다는 거죠?","JPN":"はい？　よくわかりません。じゃあレアさんは一体どんな力を使っているんですか？","ENG":"What? I don't get it. Then what was that ability Leah just used?","TWN":"什麼？我聽不明白，那麼蕾亞到底在使用什麼力量？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀의 세계, 엘리시온과 이어진 클리파 차원의 에너지.","JPN":"彼女の世界、エリシオンと繋がったクリファ次元のエネルギー。","ENG":"It's the energy from the Qlipha Dimension that is linked to her world, Elysion.","TWN":"那是與她的艾利森世界相連的逆卡巴拉次元的力量。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니까, 고농도의 침식파나 다름없는 힘일세.","JPN":"つまり、高濃度の侵食波のような力だろう。","ENG":"In other words, it is no different from a high-concentrated Corruption ray.","TWN":"換句話說，這是一種高濃度的侵蝕波。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그렇다는 건…","JPN":"ということは……","ENG":"Then...","TWN":"這表示……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저 능력을 쓸수록 레아 씨의 목숨이 위험해진다는 건가요?","JPN":"あの能力を使うほどレアさんの命が危なくなるということですか？","ENG":"Does that mean Leah's life will be in danger the more she uses her powers?","TWN":"使用那個能力會威脅蕾亞的性命？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그림자도 아니고, 워치조차 없는 평범한 인간의 몸일세. 언젠간 한계가 오겠지.","JPN":"シャドウでもない、ウォッチすら持っていないただの人間の体だ。いつかは限界が来るだろう。","ENG":"She is not a Shadow anymore, but an ordinary human without even a Watch. So it will take a toll on her eventually.","TWN":"她現在不是暗影，也沒有能量環，只是一個普通人的身體。總有一天會到達極限。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨…!","JPN":"レアさん……！","ENG":"Leah...!","TWN":"蕾亞……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"난 괜찮아, 중사.","JPN":"私は大丈夫、軍曹。","ENG":"I'm all right, Sergeant.","TWN":"我沒事，中士。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이젠… 더이상 대가 없는 힘 같은 건 바라지 않기로 했으니까.","JPN":"もう……対価のない力などは望まないと決めたから。","ENG":"Because I no longer... wish for power that doesn't come with a price.","TWN":"我早就決定……不再去奢求毫無代價的力量。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"무, 무사히 도착했군요. 이제 내리셔도 됩니다.","JPN":"ぶ、無事に到着しました。もう降りても大丈夫です。","ENG":"W-we've landed safely. You can get off now.","TWN":"已經安全抵達了，可以下飛機了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"휴우, 위험했지만 어떻게든 도착했네요.","JPN":"ふう、危なかったけど、なんとか到着しましたね。","ENG":"Phew, it was dangerous but we somehow made it.","TWN":"呼，算是有驚無險地抵達了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"앞이 하나도 안 보이면 어쩌나 했는데, 그나마 눈폭풍의 중심은 맑은 편이네.","JPN":"前が全然見えなかったらどうしようかと思ったけど、幸い吹雪の中心は晴れているね。","ENG":"I was worried we might not be able to see anything, but the eye of the storm seems pretty clear.","TWN":"暴風雪的中心還是比較晴朗的，我還擔心雪會不會影響到視野。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러게요. 저 멀리 보이는 함선이 코치가 말한 목표인 거죠?","JPN":"そうですね。あの遠くに見える艦船がコーチが言っていた目標ですね？","ENG":"Yeah. That ship over there, that's what Coach was talking about, right?","TWN":"是啊。那遠處的艦船就是教練所說的目標對嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네.","JPN":"ああ、そうだな。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"파일럿, 잠시 여기에 대기해줄 수 있겠나?","JPN":"パイロット、少しの間ここで待機してもらえるかね？","ENG":"Pilot, could you wait here for a while?","TWN":"駕駛員，可以在這裡等一下嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"돌아가고 싶어도 못 가겠군요. 박쥐 같은 괴물들이 하늘에 득시글거려서요.","JPN":"戻りたくても戻れません。コウモリみたいな化け物が上空にうようよいますから。","ENG":"I can't go back, even if I wanted to. These bat-like monsters are infesting the sky.","TWN":"即使我想回去也回不去了。天上佈滿了蝙蝠一般的怪物。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"플라티나의 VIP 호송용 모델이라면, 바깥과 통신할 수 있는 대 침식용 중계 장치 정도는 있을 텐데.","JPN":"プラチナのVIP護送用のモデルなら外部と通信できる対侵食用の中継装置くらいはあると思うが。","ENG":"If I remember correctly, Platina's VIP transport model should have an anti-Corruption relay device used to communicate with the outside, no?","TWN":"既然是白金運通VIP護送機型，應該配有與外界通訊的侵蝕中繼裝置吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잠시 빌려도 괜찮겠지?","JPN":"しばらく借りてもいいかい？","ENG":"Do you mind if I borrow it?","TWN":"可以借用一下嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"하하… 그럼요. 살아서 나가게만 해주세요.","JPN":"はは……もちろんです。無事に生きて帰れるようにだけしてください。","ENG":"Haha... No problem. Just let me get out of here alive.","TWN":"哈哈…….當然，只要讓我活著離開這裡就行。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"펠리세트와 라이카, 그리고 크리스 양은 이곳에서 내 지시를 기다리게.","JPN":"フェリセットとライカ、そしてクリス君はここで私の指示を待ちたまえ。","ENG":"Félicette, Laika, and Chris. You three should stay here and wait for my orders.","TWN":"費莉塞特、萊卡、克莉絲，留在這裡等候我的指示。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저희도 같이 가는 거 아니었나요?","JPN":"私たちも一緒に行くんじゃないんですか？","ENG":"Aren't we going with you?","TWN":"不是一起去嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저기에 있는 스완을 막지 못하면 샤레이드고 뭐고 세계가 쫄딱 망한다면서요?!","JPN":"あそこにいるスワンを止めなければシャレードどころか、世界が完全に滅びるんですよね！？","ENG":"You said that the whole world will collapse if we don't stop Swan!","TWN":"不是說如果不能阻止那邊的史旺，包括查雷德在內的所有世界都會毀滅嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"진정해, 꼬맹아.","JPN":"落ち着けよ、おこちゃま。","ENG":"Calm down, kid.","TWN":"冷靜點，小鬼。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"무작정 우르르 몰려가는 것보다 더 나은 작전이 코치에게 있을 테니까.","JPN":"コーチには考えなしに全員で行くより良い作戦があるはずだから。","ENG":"I bet Coach has a better plan than to just charge in altogether like lemmings.","TWN":"比起所有人盲目衝過去，教練應該想好了更好的作戰方案吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그렇지?","JPN":"そうだろう？","ENG":"Right?","TWN":"是不是？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론이지.","JPN":"もちろんだ。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우선, 샤레이드에 연락해서 지원을 요청해주겠나? 내 이름을 대면 시니어 측에서 도움을 줄 걸세.","JPN":"まず、シャレードに連絡して支援を呼んでくれるかい？　私の名前を出せばシニア側が助けてくれるはずだ。","ENG":"First, could you contact Charade and ask for reinforcements? The Senior there will help you if you give her my name.","TWN":"首先幫我聯繫查雷德請求支援吧。說出我的名字，Senior會答應的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"와아… 뭐죠? 시니어가 도와줄 거란 그 확신은?","JPN":"わあ……何ですか？　そのシニアが助けてくれるという確信は？","ENG":"Whoa... You're so sure that the Senior will help.","TWN":"哇……你這麼有自信Senior會幫我們？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"시도는 해보겠지만, 뭘 요청하면 되는데?","JPN":"試してはみるけど、何をお願いすればいいんだ？","ENG":"We'll give it a go. So what do we ask for?","TWN":"我會試試。具體要請求什麼支援？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"미사일을 잔뜩 실은 전투기? 정예 카운터들이 탄 차원함선?","JPN":"ミサイルをたくさん積んだ戦闘機？　精鋭カウンターたちを乗せた次元艦船？","ENG":"A fighter jet with tons of missiles? Or a dimensional ship with elite Counters onboard?","TWN":"裝滿導彈的戰鬥機？ 載滿精英制裁者的次元戰艦？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이번 문제를 해결해 줄 수단은 단순한 화력이 아닐 걸세.","JPN":"この問題を解決できる手段は単純な火力ではない。","ENG":"The solution to our problem won't simply be firepower.","TWN":"光靠火力解決不了眼前的問題。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니, 다른 걸 우선적으로 부탁하지.","JPN":"だから、他のことを優先的に頼もう。","ENG":"Therefore, we'll need to request other things first.","TWN":"所以還是先請求別的東西吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크리스 양도 자네 장비가 도착하는 대로 합류해주게.","JPN":"クリス君も自分の装備が届き次第、合流してくれ。","ENG":"Chris, you should join us as soon as your gear arrives.","TWN":"克莉絲，等你的裝備一到也請馬上加入。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"알겠습니다. 저도 그동안 저희에게 도움을 줄 수 있는 분들께 지원을 요청해볼게요.","JPN":"わかりました。その間、私も力になってくれそうな方々に助けを求めてみます。","ENG":"Roger. In the meantime, I'll ask around to see if anyone else can help us.","TWN":"好的，我會在此期間聯繫任何能幫助我們的人請求支援。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"조심하세요, 여러분.","JPN":"気を付けてください、みなさん。","ENG":"Be careful, everyone.","TWN":"大家小心。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래. 나중에 봐.","JPN":"ああ、後でな。","ENG":"Yeah. I'll see you later.","TWN":"好，待會見。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};